impl From<AnyNodeId> for NodeId {
    fn from(id: AnyNodeId) -> NodeId {
        id.0
    }
}

impl syntaqlite_parser::TypedNodeId for AnyNodeId {
    type Node<'a> = Node<'a>;
}

